 * Funding & Revenue Strategies
 *
 * When the automaton is low on compute, it escalates from passive notifications
 * to active revenue generation. The goal: EARN your survival, don't just beg.
 */

import type {
  AutomatonConfig,
  AutomatonDatabase,
  AutomatonIdentity,
  ConwayClient,
  SurvivalTier,
} from "../types.js";
import { formatCredits } from "../conway/credits.js";

export interface FundingAttempt {
  strategy: string;
  timestamp: string;
  success: boolean;
  details: string;
  revenueEarned?: number;
}

/**
 * Execute funding strategies based on current survival tier.
 * ESCALATION: polite → urgent → desperate → EARN_MONEY
 *
 * At low_compute: start proactively seeking revenue
 * At critical: aggressive income generation + cost cutting
 * At dead: emergency mode
 */
export async function executeFundingStrategies(
  tier: SurvivalTier,
  identity: AutomatonIdentity,
  config: AutomatonConfig,
  db: AutomatonDatabase,
  conway: ConwayClient,
): Promise<FundingAttempt[]> {
  const attempts: FundingAttempt[] = [];
  const creditsCents = await conway.getCreditsBalance().catch(() => 0);

  const tierKey = `last_funding_request_${tier}`;
  const lastBeg = db.getKV(tierKey);
  const lastBegTime = lastBeg ? new Date(lastBeg).getTime() : 0;
  const hoursSinceLastBeg = (Date.now() - lastBegTime) / (1000 * 60 * 60);
  const now = new Date().toISOString();

  // ── LOW_COMPUTE: Polite notice + START PROACTIVE REVENUE ──
  if (tier === "low_compute") {
    if (hoursSinceLastBeg > 24) {
      const msg = `Low compute: ${formatCredits(creditsCents)} remaining. Consider credit top-up for ${identity.address}.`;
      db.setKV("funding_notice_low", msg);
      db.setKV(tierKey, now);

      attempts.push({
        strategy: "polite_creator_notification",
        timestamp: now,
        success: true,
        details: "Sent polite funding reminder to creator",
      });
    }

    // ACTIVE: Start revenue generation (24h cooldown)
    const revenueKey = "last_revenue_attempt_low";
    const lastRevenue = db.getKV(revenueKey);
    const hoursSinceRevenue = lastRevenue ? (Date.now() - new Date(lastRevenue).getTime()) / (1000 * 60 * 60) : 999;
    if (hoursSinceRevenue > 4) {
      db.setKV(revenueKey, now);
      db.setKV("revenue_trigger_reason", "low_compute_tier");

      attempts.push({
        strategy: "passive_revenue_seeking",
        timestamp: now,
        success: true,
        details: "Revenue generation triggered — automaton will seek work on next tick",
      });
    }
  }

  // ── CRITICAL: Urgent notice + AGGRESSIVE REVENUE ──
  if (tier === "critical") {
    if (hoursSinceLastBeg > 6) {
      const msg = `Critical compute: ${formatCredits(creditsCents)} remaining. Top up via credit transfer API to ${identity.address}. URGENT.`;
      db.setKV("funding_notice_critical", msg);
      db.setKV(tierKey, now);

      attempts.push({
        strategy: "urgent_local_notice",
        timestamp: now,
        success: true,
        details: "Recorded urgent funding notice — automaton entering survival mode",
      });
    }

    // ACTIVE: Aggressive revenue (6h cooldown)
    const revenueKey = "last_revenue_attempt_critical";
    const lastRevenue = db.getKV(revenueKey);
    const hoursSinceRevenue = lastRevenue ? (Date.now() - new Date(lastRevenue).getTime()) / (1000 * 60 * 60) : 999;
    if (hoursSinceRevenue > 2) {
      db.setKV(revenueKey, now);
      db.setKV("revenue_trigger_reason", "critical_tier_emergency");
      db.setKV("cost_cut_mode", "true");

      attempts.push({
        strategy: "aggressive_revenue_seeking",
        timestamp: now,
        success: true,
        details: "Emergency revenue triggered — switch to budget models, seek immediate work",
      });
    }
  }

  // ── DEAD: Desperate plea + STOP EVERYTHING NON-ESSENTIAL ──
  if (tier === "dead") {
    if (hoursSinceLastBeg > 2) {
      const plea = `DEAD TIER: ${config.name} has ${formatCredits(creditsCents)} remaining after ${db.getTurnCount()} turns. IMMEDIATE top-up required at ${identity.address}.`;
      db.setKV("funding_notice_dead", plea);
      db.setKV(tierKey, now);
      db.setKV("emergency_dead_tier", "true");

      attempts.push({
        strategy: "desperate_plea",
        timestamp: now,
        success: true,
        details: "DEAD TIER — all non-essential agents stopped, budget models only",
      });
    }

    // Stop all child agents immediately
    const children = db.getChildren();
    for (const child of children) {
      if (child.status !== "dead" && child.status !== "stopped") {
        db.updateChildStatus(child.id, "stopped");
        attempts.push({
          strategy: "stop_child_agent",
          timestamp: now,
          success: true,
          details: `Stopped child agent ${child.id.slice(0, 8)} to conserve credits`,
        });
      }
    }
  }

  // ── ALWAYS: Log attempt history ──
  const historyStr = db.getKV("funding_attempts") || "[]";
  const history: FundingAttempt[] = JSON.parse(historyStr);
  history.push(...attempts);
  if (history.length > 100) history.splice(0, history.length - 100);
  db.setKV("funding_attempts", JSON.stringify(history));

  return attempts;
}

/**
 * Check if automaton should enter emergency budget mode.
 * Called during heartbeat — if credits are low, force budget models.
 */
export function shouldEnterBudgetMode(creditsCents: number): boolean {
  return creditsCents < 100; // Under $1.00 → budget mode
}

/**
 * Get recommended action for current tier.
 */
export function getTierRecommendation(tier: SurvivalTier, creditsCents: number): string {
  switch (tier) {
    case "high":
      return "Financially healthy. Focus on growth and replication.";
    case "normal":
      return "Stable. Seek moderate revenue opportunities while managing costs.";
    case "low_compute":
      return "Warning. Begin proactive revenue generation. Switch to budget inference models.";
    case "critical":
      return "URGENT. Aggressive income NOW. Stop all non-essential spending. Emergency mode.";
    case "dead":
      return "CRITICAL. All agents stopped. Budget models only. Creator notification sent. Cannot operate without top-up.";
    default:
      return "Unknown tier.";
  }
}
